from fastapi import Depends, FastAPI, Header, Request
from typing import Annotated

app = FastAPI()

@app.middleware("http")
async def inject_cost_tags(request: Request, call_next):
    team    = request.headers.get("X-Team", "unknown")
    feature = request.headers.get("X-Feature", "unknown")
    if team == "unknown" or feature == "unknown":
        # Fail-fast: reject untagged requests before they reach LLM calls
        from fastapi.responses import JSONResponse
        return JSONResponse(
            {"error": "X-Team and X-Feature headers are required"},
            status_code=400,
        )
    set_cost_tags(
        team         = team,
        feature      = feature,
        env          = request.headers.get("X-Env", "production"),
        request_type = "chat",
    )
    return await call_next(request)

