from collections import defaultdict
from dataclasses import dataclass

@dataclass
class AllocationRule:
    pool_feature: str           # e.g. "shared-embed"
    split_by_tag: str = "team"  # tag whose values determine the split

def proportional_split(
    records: list[TokenCostRecord],
    rule: AllocationRule,
) -> dict[str, float]:
    """Return {team: allocated_cost_usd} for a pool feature."""
    pool_records = [r for r in records if r.tags.get("feature") == rule.pool_feature]
    token_by_tag: dict[str, int] = defaultdict(int)
    for rec in pool_records:
        key = rec.tags.get(rule.split_by_tag, "untagged")
        token_by_tag[key] += rec.prompt_tokens + rec.completion_tokens
    total_tokens = sum(token_by_tag.values()) or 1
    total_cost   = sum(r.cost_usd for r in pool_records)
    return {
        tag: total_cost * (tokens / total_tokens)
        for tag, tokens in token_by_tag.items()
    }

# Internal rates (USD per 1 000 tokens) — reviewed quarterly
INTERNAL_RATE: dict[str, dict[str, float]] = {
    "gpt-4o":            {"input": 0.003,  "output": 0.012},
    "gpt-4o-mini":       {"input": 0.0002, "output": 0.0008},
    "claude-sonnet-4-6": {"input": 0.004,  "output": 0.018},
    # Embeddings billed per 1K tokens input only
    "text-embedding-3-large": {"input": 0.0002, "output": 0.0},
}

def internal_chargeback_cost(rec: TokenCostRecord) -> float:
    rates = INTERNAL_RATE.get(rec.model, {"input": 0.0, "output": 0.0})
    return (
        rec.prompt_tokens     / 1_000 * rates["input"] +
        rec.completion_tokens / 1_000 * rates["output"]
    )

def monthly_chargeback_report(
    records: list[TokenCostRecord],
    year_month: str,   # "2025-06"
) -> dict[str, float]:
    """Return {team: chargeback_usd} for a calendar month."""
    monthly = [
        r for r in records
        if r.timestamp_utc.startswith(year_month)
        and r.tags.get("env") == "production"  # exclude dev/staging
    ]
    totals: dict[str, float] = defaultdict(float)
    for rec in monthly:
        team = rec.tags.get("team", "untagged")
        totals[team] += internal_chargeback_cost(rec)
    return dict(totals)

import threading
from dataclasses import dataclass, field

@dataclass
class TeamBudget:
    team:          str
    monthly_cap:   float          # USD
    warn_threshold: float = 0.80  # fraction
    spent:         float = field(default=0.0, init=False)
    _lock:         threading.Lock = field(default_factory=threading.Lock, init=False, repr=False)

    def record_spend(self, amount: float) -> None:
        with self._lock:
            self.spent += amount

    @property
    def utilisation(self) -> float:
        return self.spent / self.monthly_cap if self.monthly_cap else 0.0

    def check(self) -> str:
        """Return 'ok', 'warn', or 'block'."""
        u = self.utilisation
        if u >= 1.0:
            return "block"
        if u >= self.warn_threshold:
            return "warn"
        return "ok"

class BudgetGate:
    def __init__(self, budgets: list[TeamBudget]) -> None:
        self._budgets = {b.team: b for b in budgets}

    def pre_call_check(self, tags: dict[str, str]) -> None:
        team   = tags.get("team", "untagged")
        budget = self._budgets.get(team)
        if budget is None:
            return  # no budget defined — allow
        status = budget.check()
        if status == "block":
            raise PermissionError(
                f"Team '{team}' has exhausted its monthly LLM budget "
                f"(${budget.monthly_cap:.2f}). "
                "Request a budget increase via the FinOps portal."
            )
        if status == "warn":
            # Emit a warning metric; do not block
            print(f"[BUDGET-WARN] {team} at {budget.utilisation:.0%} of monthly cap")

    def record(self, rec: TokenCostRecord) -> None:
        team   = rec.tags.get("team", "untagged")
        budget = self._budgets.get(team)
        if budget:
            budget.record_spend(rec.cost_usd)
